settings.custom_liquid:
{%- if collection.description != blank -%}
<style>
  .diy-collapsible-wrap {
    --lab-red:  #C8102E;
    --carbon:   #0A0A0A;
    --bone:     #F5F2EC;
    --steel:    #AAAAAA;
    background: var(--carbon);
    border-radius: 2px;
    padding: 0;
    position: relative;
    margin: 2rem 0;
    border-left: 3px solid var(--lab-red);
  }
  .diy-toggle-btn {
    display: flex; align-items: center; justify-content: space-between;
    gap: 16px; width: 100%; background: none; border: none;
    border-bottom: 1px solid #1f1f1f;
    padding: 18px 24px 18px 28px; cursor: pointer; text-align: left;
    transition: background 0.2s;
  }
  .diy-toggle-btn:hover { background: rgba(200,16,46,0.04); }
  .diy-eyebrow {
    font-size: 10px; font-weight: 700; letter-spacing: 0.2em;
    text-transform: uppercase; color: var(--lab-red);
    display: block; margin-bottom: 6px;
  }
  .diy-title-text {
    font-size: 14px; font-weight: 600; color: var(--bone);
    line-height: 1.4; transition: color 0.2s; display: block;
  }
  .diy-toggle-btn:hover .diy-title-text { color: #FFFFFF; }
  .diy-icon {
    flex-shrink: 0; width: 26px; height: 26px;
    border: 1px solid #2e2e2e; border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    position: relative; transition: border-color 0.2s;
  }
  .diy-toggle-btn:hover .diy-icon,
  .diy-toggle-btn.open .diy-icon { border-color: var(--lab-red); }
  .diy-icon-bar {
    position: absolute; background: #555; border-radius: 1px;
    transition: transform 0.28s ease, opacity 0.28s ease, background 0.2s;
  }
  .diy-icon-bar.h { width: 10px; height: 1.5px; }
  .diy-icon-bar.v { width: 1.5px; height: 10px; }
  .diy-toggle-btn:hover .diy-icon-bar,
  .diy-toggle-btn.open .diy-icon-bar { background: var(--lab-red); }
  .diy-toggle-btn.open .diy-icon-bar.v { transform: rotate(90deg); opacity: 0; }
  .diy-content-outer {
    overflow: hidden; max-height: 0; opacity: 0;
    transition: max-height 0.42s cubic-bezier(0.4,0,0.2,1), opacity 0.32s ease;
  }
  .diy-content-outer.open { opacity: 1; }
  .diy-content-inner { padding: 20px 28px 28px; line-height: 1.8; }
  .diy-divider {
    display: block; height: 1px; margin-bottom: 20px; opacity: 0.5;
    background: linear-gradient(to right, var(--lab-red) 0%, #2a0008 60%, transparent 100%);
  }
  .diy-rich-text * { color: var(--steel) !important; }
  .diy-rich-text h1, .diy-rich-text h2,
  .diy-rich-text h3, .diy-rich-text h4 {
    font-size: 15px !important; font-weight: 700 !important;
    color: var(--bone) !important; margin: 0 0 14px !important;
    line-height: 1.35 !important;
  }
  .diy-rich-text p {
    color: var(--steel) !important;
    margin: 0 0 12px !important; font-size: 14px !important;
  }
  .diy-rich-text p:last-child { margin-bottom: 0 !important; }
  .diy-rich-text a {
    color: var(--lab-red) !important;
    text-decoration: underline !important;
    text-underline-offset: 3px !important;
  }
  .diy-rich-text a:hover { color: #ff2040 !important; }
  .diy-rich-text strong, .diy-rich-text b {
    color: var(--bone) !important; font-weight: 600 !important;
  }
  .diy-rich-text ul, .diy-rich-text ol {
    color: var(--steel) !important;
    padding-left: 18px !important; margin: 0 0 12px !important;
  }
  .diy-rich-text li { color: var(--steel) !important; margin-bottom: 4px !important; }
</style>

<div class="diy-collapsible-wrap">
  <button
    class="diy-toggle-btn"
    id="diyToggle-{{ collection.id }}"
    onclick="toggleDiyBlock('{{ collection.id }}')"
    aria-expanded="false"
    aria-controls="diyContent-{{ collection.id }}"
  >
    <span>
      <span class="diy-eyebrow">DIY Vape Shop · Guía de colección</span>
      <span class="diy-title-text">
        ¿Quieres saber más de
        <em style="font-style:normal;color:var(--lab-red);">{{ collection.title }}</em>
        y todo lo relacionado con el mundo del Vapeo?
      </span>
    </span>
    <span class="diy-icon" id="diyIcon-{{ collection.id }}">
      <span class="diy-icon-bar h"></span>
      <span class="diy-icon-bar v"></span>
    </span>
  </button>

  <div class="diy-content-outer" id="diyContent-{{ collection.id }}">
    <div class="diy-content-inner">
      <span class="diy-divider"></span>
      <div class="diy-rich-text">
        {{ collection.description }}
      </div>
    </div>
  </div>
</div>

<script>
function toggleDiyBlock(id) {
  var btn = document.getElementById('diyToggle-' + id);
  var content = document.getElementById('diyContent-' + id);
  var isOpen = btn.classList.contains('open');
  if (isOpen) {
    content.style.maxHeight = content.scrollHeight + 'px';
    requestAnimationFrame(function() {
      content.style.maxHeight = '0px';
      content.classList.remove('open');
      btn.classList.remove('open');
      btn.setAttribute('aria-expanded','false');
    });
  } else {
    btn.classList.add('open');
    content.classList.add('open');
    content.style.maxHeight = content.scrollHeight + 'px';
    btn.setAttribute('aria-expanded','true');
    content.addEventListener('transitionend', function() {
      if (btn.classList.contains('open')) content.style.maxHeight = 'none';
    }, { once: true });
  }
}
</script>
{%- endif -%}
